# Mem0 basic setup and add/search operations
# pip install mem0ai

from mem0 import Memory

# Default config: Qdrant vector store + OpenAI embeddings
# Override embedder to use Voyage + Qdrant explicitly
config = {
    "vector_store": {
        "provider": "qdrant",
        "config": {
            "collection_name": "agent_memories",
            "host": "localhost",
            "port": 6333,
            "embedding_model_dims": 1024,
        },
    },
    "embedder": {
        "provider": "voyageai",
        "config": {
            "model": "voyage-3",
            "embedding_dims": 1024,
        },
    },
    "llm": {
        "provider": "anthropic",
        "config": {
            "model": "claude-haiku-4-5-20251001",
            "temperature": 0.0,
            "max_tokens": 512,
        },
    },
}

m = Memory.from_config(config)

# Add memories from a conversation
messages = [
    {"role": "user",      "content": "The project budget is $80k and the deadline is December 15."},
    {"role": "assistant", "content": "Got it — I'll remember the $80k budget and December 15 deadline."},
    {"role": "user",      "content": "We are using FastAPI and PostgreSQL 16."},
]
result = m.add(messages, user_id="u_42", agent_id="project_bot")
# result contains a list of memory operations: ADD, UPDATE, or NONE per extracted fact
for r in result.get("results", []):
    print(f"[{r['event']}] {r['memory']}")
